514       return CR1;
515     if (CR1.isSignWrappedSet() && !CR2.isSignWrappedSet())
516       return CR2;
517   }
518 
519   if (CR1.isSizeStrictlySmallerThan(CR2))
520     return CR1;
521   return CR2;
